+		t.Fatalf("expected 2 search results, got %d", len(results))
+	}
+	if _, err := st.Search(ctx, MessageFilter{}); err == nil {
+		t.Fatal("expected empty search query error")
+	}
+
+	after := now.Add(-2 * time.Minute)
+	before := now.Add(time.Minute)
